    let headerBody; if (topFill < 0) headerBody = `${fit(`─${topLabel}`, inner - 1)}─`; else { const actions = visibleActions.map((action, index) => { const active = navigation.activeAction === action; const hovered = navigation.rail === 'actions' && navigation.action === index; return active || hovered ? `${COLORS.bgYellow}${COLORS.black}${COLORS.bold}[${action}]${COLORS.reset}${color}` : `[${action}]`; }).join(' '); headerBody = `─${topLabel}${'─'.repeat(topFill)}${actions}─`; }
