  launchVerifier({ execution, integration, context, profile }) { const prompt = `You are the fresh read-only BDFL verifier. Inspect the consolidated diff and approved plan context at ${context}. Do not edit files. Report pass or fail through bdfl_workers complete, naming affected chunk IDs when possible.`; const session = this.store.createSession(execution.workstreamId, 'verifier', profile, { executionId: execution.id, worktree: integration.worktree, taskSnippet: `Verify ${execution.planId}`, roleInstruction: prompt }); this.sessions.open(session.id, this.dimensions()); return { sessionId: session.id }; }
  launchIntegrationWorker({ execution, integration, allowedPaths, profile }) { const prompt = `Resolve only the recorded cherry-pick conflict in ${integration.worktree}. Changes are restricted to: ${allowedPaths.join(', ')}. Do not broaden the implementation. Call bdfl_workers complete when the conflict is repaired.`; const session = this.store.createSession(execution.workstreamId, 'integration', profile, { executionId: execution.id, worktree: integration.worktree, taskSnippet: `Resolve integration for ${execution.planId}`, roleInstruction: prompt }); this.sessions.open(session.id, this.dimensions()); return { sessionId: session.id }; }
  acquire() { fs.mkdirSync(path.dirname(this.lockFile), { recursive: true }); for (let attempt = 0; attempt < 2; attempt += 1) { try { this.lock = fs.openSync(this.lockFile, 'wx', 0o600); fs.writeFileSync(this.lock, `${process.pid}\n`); return; } catch (error) { if (error.code !== 'EEXIST') throw error; let owner; try { owner = Number.parseInt(fs.readFileSync(this.lockFile, 'utf8'), 10); } catch {} let alive = Number.isInteger(owner) && owner > 0; if (alive) { try { process.kill(owner, 0); } catch (probe) { if (probe.code === 'ESRCH') alive = false; } } if (alive || attempt) throw new Error('Another BDFL supervisor owns this workspace'); try { fs.unlinkSync(this.lockFile); } catch (remove) { if (remove.code !== 'ENOENT') throw remove; } } } }
