  planItems() { const directory = path.join(this.root, '.bdfl', 'plans'); let entries; try { entries = fs.readdirSync(directory, { withFileTypes: true }); } catch { return []; } return entries.filter((entry) => entry.isDirectory()).flatMap((entry) => { try { return [JSON.parse(fs.readFileSync(path.join(directory, entry.name, 'lineage.json'), 'utf8'))]; } catch { return []; } }).sort((a, b) => `${b.updatedAt}`.localeCompare(`${a.updatedAt}`)); }
  planAgentLines(lineage, prefix = '') { const workspace = this.workspace || this.store.load(); const planning = workspace.sessions.find((session) => session.id === lineage.originSessionId); const stream = workspace.workstreams.find((item) => item.id === lineage.workstreamId); const planningText = planning?.name || 'Unavailable'; const profile = stream?.workerProfile; const workerText = stream && profile ? `${display(profile.provider)}${profile.model ? ` ${profile.model}` : ''}${profile.effort ? ` · ${profile.effort} effort` : ''} · max ${stream.workerCapacity}` : 'Unavailable'; const row = (connector, label, detail) => `${COLORS.gray}${prefix}${connector}${COLORS.reset} ${COLORS.bold}${COLORS.white}${label}${COLORS.reset}${COLORS.gray} · ${detail}${COLORS.reset}`; return [row('├─', 'Planning agent', planningText), row('└─', 'Worker agent', workerText)]; }
